  constructor(private fb: FormBuilder, private dialogService: AavaDialogService, private router: Router) {
    this.form = this.fb.group({
      ex1: [2],
      ex2: [1],
      ex3: [3],
      ex4: [4],
      ex5: ['all']

    });
    // this.sform = this.fb.group({
    //   fsex1: ['simple-rule-3', { disabled: true }],
    //   fsex2: ['simple-rule-1'],

    // });

    this.form = new FormGroup({
      ex1: new FormControl({ value: 1, disabled: false }),
      ex2: new FormControl({ value: 'travel', disabled: false }),
      ex3: new FormControl(4),
      ex4: new FormControl(2),
      ex5: new FormControl({ value: 'technology', disabled: true }),

    });

    this.sform = new FormGroup({
      fsex1: new FormControl({ value: 'simple-rule-3', disabled: true }),
      fsex2: new FormControl('simple-rule-1',)
    });
  }
